import { _decorator, Component, director, Node, Label, Button, ScrollView, Prefab, instantiate } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('TempleScene')
export class TempleScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(ScrollView)
    godsScrollView: ScrollView = null;
    
    @property(Node)
    godCardPrefab: Node = null;
    
    @property(Label)
    incenseSticksLabel: Label = null;
    
    @property(Label)
    candlesLabel: Label = null;
    
    @property(Label)
    goldPaperLabel: Label = null;
    
    @property(Label)
    fruitsLabel: Label = null;
    
    private gods = [
        { id: 'caishen', name: '赵公明', title: '正财神', effect: '香火钱+20%' },
        { id: 'wencaishen', name: '比干', title: '文财神', effect: '法力上限+10' },
        { id: 'wucaishen', name: '关公', title: '武财神', effect: '化缘收益+15%' },
        { id: 'piancaishen', name: '范蠡', title: '偏财神', effect: '暴击率+5%' },
        { id: 'shengcai', name: '李诡祖', title: '增福财神', effect: '供奉功德+10%' },
        { id: 'lucaishen', name: '沈万三', title: '禄财神', effect: '法力回复+20%' },
        { id: 'shoucaishen', name: '刘海蟾', title: '寿财神', effect: '香火钱上限+1000' },
        { id: 'xicaishen', name: '子贡', title: '喜财神', effect: '每日首供双倍' },
        { id: 'caishenpo', name: '财神奶奶', title: '财神婆婆', effect: '化缘风险-10%' }
    ];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.initGodsList();
        this.updateResources();
    }
    
    initGodsList() {
        const content = this.godsScrollView.content;
        content.removeAllChildren();
        
        for (const god of this.gods) {
            const card = instantiate(this.godCardPrefab);
            card.getChildByName('NameLabel').getComponent(Label).string = god.name;
            card.getChildByName('TitleLabel').getComponent(Label).string = god.title;
            card.getChildByName('EffectLabel').getComponent(Label).string = god.effect;
            
            const worshipBtn = card.getChildByName('WorshipBtn').getComponent(Button);
            worshipBtn.node.on(Button.EventType.CLICK, () => this.onWorshipGod(god.id), this);
            
            content.addChild(card);
        }
    }
    
    updateResources() {
        const player = GameManager.getInstance().playerData;
        this.incenseSticksLabel.string = `线香: ${player.getCurrency('incense_sticks')}`;
        this.candlesLabel.string = `蜡烛: ${player.getCurrency('candles')}`;
        this.goldPaperLabel.string = `金纸: ${player.getCurrency('gold_paper')}`;
        this.fruitsLabel.string = `供果: ${player.getCurrency('fruits')}`;
    }
    
    async onWorshipGod(godId: string) {
        GameManager.getInstance().showLoading('供奉中...');
        
        try {
            const result = await GameManager.getInstance().network.post('/api/temple/worship', {
                godId: godId,
                offeringType: 'incense_sticks',
                offeringLevel: 1
            });
            
            if (result.success) {
                // 更新本地数据
                GameManager.getInstance().playerData.addCurrency('incense_money', result.reward.incense_money);
                GameManager.getInstance().playerData.addCurrency('merit', result.reward.merit);
                GameManager.getInstance().playerData.costCurrency('incense_sticks', 1);
                
                this.updateResources();
                // 显示奖励提示
            } else {
                // 显示错误提示
                console.log(result.message);
            }
        } catch (error) {
            console.error('供奉错误:', error);
        } finally {
            GameManager.getInstance().hideLoading();
        }
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
